<?php
 namespace League\CommonMark\Block\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\ListBlock; use League\CommonMark\ElementRendererInterface; use League\CommonMark\HtmlElement; final class ListBlockRenderer implements BlockRendererInterface { public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof ListBlock)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } $listData = $block->getListData(); $tag = $listData->type === ListBlock::TYPE_BULLET ? 'ul' : 'ol'; $attrs = $block->getData('attributes', []); if ($listData->start !== null && $listData->start !== 1) { $attrs['start'] = (string) $listData->start; } return new HtmlElement( $tag, $attrs, $htmlRenderer->getOption('inner_separator', "\n") . $htmlRenderer->renderBlocks( $block->children(), $block->isTight() ) . $htmlRenderer->getOption('inner_separator', "\n") ); } } 